  "cases": [
    {
      "input": {
        "action": "scope",
        "ops": [
          {
            "op": "create_root",
            "id": "r"
          },
          {
            "op": "build_child",
            "id": "c1",
            "parent": "r",
            "name": "child1"
          },
          {
            "op": "build_child",
            "id": "c2",
            "parent": "r",
            "name": "child2"
          },
          {
            "op": "build_child",
            "id": "c3",
            "parent": "r",
            "name": "child3"
